+fn result_bytes_saved() {
+    let mut pipeline = CompressionPipeline::new(epoch(10));
+    let d = desc(
+        "save-test",
+        ArtifactDomain::Cache,
+        ArtifactFamily::CacheEntry,
+        5000,
+        None,
